+impl ColorTransform {
+    fn apply(self, color: Color) -> Color {
+        let (r, g, b) = if let Some((r, g, b)) = color.as_rgb() {
+            (r, g, b)
+        } else if let Some(n) = color.as_ansi() {
+            ansi256_to_rgb(n)
+        } else {
+            return color;
+        };
+
+        let (h, mut s, mut l) = rgb_to_hsl(r, g, b);
+        let amount = |v: f32| v.max(0.0).min(1.0);
+
+        match self {
+            ColorTransform::Lighten(a) => l = (l + amount(a)).min(1.0),
+            ColorTransform::Darken(a) => l = (l - amount(a)).max(0.0),
+            ColorTransform::Saturate(a) => s = (s + amount(a)).min(1.0),
+            ColorTransform::Desaturate(a) => s = (s - amount(a)).max(0.0),
+            ColorTransform::Alpha(a) => {
+                let a = amount(a);
+                l = (l * a).min(1.0);
+            }
+        }
+
+        let (nr, ng, nb) = hsl_to_rgb(h, s, l);
+        Color::from(format!("#{:02x}{:02x}{:02x}", nr, ng, nb))
+    }
+}
+
+fn rgb_to_hsl(r: u8, g: u8, b: u8) -> (f32, f32, f32) {
+    let r = r as f32 / 255.0;
+    let g = g as f32 / 255.0;
+    let b = b as f32 / 255.0;
+
+    let max = r.max(g).max(b);
+    let min = r.min(g).min(b);
+    let l = (max + min) / 2.0;
+
+    if (max - min).abs() < f32::EPSILON {
+        return (0.0, 0.0, l);
+    }
+
+    let d = max - min;
+    let s = if l > 0.5 {
+        d / (2.0 - max - min)
+    } else {
+        d / (max + min)
+    };
+
+    let mut h = if (max - r).abs() < f32::EPSILON {
+        (g - b) / d + if g < b { 6.0 } else { 0.0 }
+    } else if (max - g).abs() < f32::EPSILON {
+        (b - r) / d + 2.0
+    } else {
+        (r - g) / d + 4.0
+    };
+
+    h /= 6.0;
+    (h * 360.0, s, l)
+}
+
+fn hsl_to_rgb(h: f32, s: f32, l: f32) -> (u8, u8, u8) {
+    if s == 0.0 {
+        let v = (l * 255.0).round() as u8;
+        return (v, v, v);
+    }
+
+    let h = h / 360.0;
+    let q = if l < 0.5 {
+        l * (1.0 + s)
+    } else {
+        l + s - l * s
+    };
+    let p = 2.0 * l - q;
+
+    fn hue_to_rgb(p: f32, q: f32, mut t: f32) -> f32 {
+        if t < 0.0 {
+            t += 1.0;
+        }
+        if t > 1.0 {
+            t -= 1.0;
+        }
+        if t < 1.0 / 6.0 {
+            return p + (q - p) * 6.0 * t;
+        }
+        if t < 1.0 / 2.0 {
+            return q;
+        }
+        if t < 2.0 / 3.0 {
+            return p + (q - p) * (2.0 / 3.0 - t) * 6.0;
+        }
+        p
+    }
+
+    let r = hue_to_rgb(p, q, h + 1.0 / 3.0);
+    let g = hue_to_rgb(p, q, h);
+    let b = hue_to_rgb(p, q, h - 1.0 / 3.0);
+
+    (
+        (r * 255.0).round() as u8,
+        (g * 255.0).round() as u8,
+        (b * 255.0).round() as u8,
+    )
+}
